test("parses two blocks", () => {
  const response = `File: src/a.ts
<<<<<<< SEARCH
old_a
=======
new_a
>>>>>>>`
    + `

File: src/b.ts
<<<<<<< SEARCH
old_b
=======
new_b
>>>>>>>`;
  const blocks = parseEditBlocks(response);
  expect(blocks.length).toBe(2);
});
